const execution = $json.execution || {};
const workflow = $json.workflow || {};
const error = execution.error || {};

const workflowName = workflow.name || 'Unknown';
const workflowId = workflow.id || '';
const errorMessage = error.message || error.description || 'Unknown error';
const errorStack = error.stack || '';
const executionUrl = execution.url || '';
const executionId = execution.id || '';
const lastNode = execution.lastNodeExecuted || '';
const nodeName = error.node?.name || lastNode;
const triggerType = execution.executionContext?.source || execution.mode || 'unknown';
const triggerNode = execution.executionContext?.triggerNode?.name || '';

// --- LOOP DETECTION ---
const isLoop = workflowName.includes('MX_00_Event_Router');

// --- TRANSIENT ERROR CLASSIFICATION ---
const transientPatterns = [
  'connection timed out',
  'econnreset',
  'econnrefused',
  'eai_again',
  'unable to check out connection',
  'failed to subscribe to tenant',
  'overloaded',
  'overloaded_error',
  'status code 429',
  'status code 502',
  'status code 503',
  'status code 529',
  'etimedout',
  'socket hang up',
  'network timeout',
  'request timeout',
  'too many requests',
  'service unavailable',
  'bad gateway'
];

const errorLower = (errorMessage + ' ' + (error.description || '')).toLowerCase();
const isTransient = transientPatterns.some(p => errorLower.includes(p));

// --- CATEGORY ---
let category;
if (isLoop) {
  category = 'loop';
} else if (isTransient) {
  category = 'transient';
} else {
  category = 'persistent';
}

return {
  json: {
    workflow_name: workflowName,
    workflow_id: workflowId,
    execution_id: executionId,
    execution_url: executionUrl,
    error_message: errorMessage,
    error_stack: errorStack,
    error_node: nodeName,
    trigger_type: triggerType,
    trigger_node: triggerNode,
    is_loop: isLoop,
    is_transient: isTransient,
    category: category,
    raw_payload: JSON.stringify($json)
  }
};

